#!/usr/bin/env python3
"""validate_flags.py — CI gate for flag registry consistency."""
import ast, os, re, sys, yaml
from datetime import date
from pathlib import Path

REGISTRY = Path("config/flags.yml")
SRC_DIR  = Path("src")
REQUIRED_FIELDS = {"description", "owner", "team", "state", "expires_after", "rollback_env_var"}
VALID_STATES = {"registered", "default_off", "canary", "full_on", "retired"}

def load_registry() -> dict:
    with open(REGISTRY) as f:
        return yaml.safe_load(f)["flags"]

def flags_in_source() -> set[str]:
    """Find all FEATURE_* env var names referenced in Python source."""
    pattern = re.compile(r'os\.getenv\(["\'](FEATURE_[A-Z_]+)["\']]')
    found = set()
    for py_file in SRC_DIR.rglob("*.py"):
        text = py_file.read_text()
        for match in pattern.finditer(text):
            found.add(match.group(1).lower().removeprefix("feature_"))
    return found

def validate(registry: dict, code_flags: set[str]) -> list[str]:
    errors = []
    today = date.today()

    for name, cfg in registry.items():
        # Required fields
        missing = REQUIRED_FIELDS - set(cfg)
        if missing:
            errors.append(f"Flag '{name}': missing fields {missing}")

        # Valid state
        if cfg.get("state") not in VALID_STATES:
            errors.append(f"Flag '{name}': invalid state '{cfg.get('state')}'")

        # Expiry
        if "expires_after" in cfg:
            exp = date.fromisoformat(str(cfg["expires_after"]))
            if exp < today and cfg.get("state") not in ("retired",):
                errors.append(
                    f"Flag '{name}': expired {cfg['expires_after']} — "
                    f"remove flag and code, or extend expires_after"
                )

        # State-specific checks
        if cfg.get("state") == "canary" and "canary_pct" not in cfg:
            errors.append(f"Flag '{name}': canary state requires canary_pct")

    # All code flags must be registered
    for flag in code_flags:
        if flag not in registry:
            errors.append(f"Flag 'FEATURE_{flag.upper()}' used in code but not in registry")

    return errors

if __name__ == "__main__":
    registry = load_registry()
    code_flags = flags_in_source()
    errors = validate(registry, code_flags)
    if errors:
        print("Flag registry validation FAILED:")
        for e in errors:
            print(f"  - {e}")
        sys.exit(1)
    print(f"Flag registry OK: {len(registry)} flags, {len(code_flags)} referenced in code.")

# src/response.py — consuming a flag via the registry
from src.flags import is_enabled
from src.cache import get_cached_response, cache_response

def generate(prompt: str) -> str:
    if is_enabled("cache_streaming"):
        cached = get_cached_response(prompt)
        if cached:
            return cached

    result = _call_model(prompt)

    if is_enabled("cache_streaming"):
        cache_response(prompt, result)

    return result
